from flask import Flask, request, Response
from prometheus_client import Counter, CollectorRegistry, generate_latest, CONTENT_TYPE_LATEST
import os

app = Flask(__name__)

registry = CollectorRegistry()

REQUESTS_TOTAL = Counter(
    "http_requests_total",
    "Total HTTP requests labeled by user, session, and full request path",
    ["user_id", "session_id", "path"],
    registry=registry,
)

DYNAMIC_USER_PATH_COUNTERS = {}

def sanitize_metric_part(value: str) -> str:
    cleaned = []
    for ch in value.lower():
        if ch.isalnum():
            cleaned.append(ch)
        else:
            cleaned.append("_")
    result = "".join(cleaned).strip("_")
    if not result:
        result = "unknown"
    if result[0].isdigit():
        result = f"m_{result}"
    return result

def get_or_create_user_path_counter(user_id: str, path: str) -> Counter:
    key = (user_id, path)
    if key in DYNAMIC_USER_PATH_COUNTERS:
        return DYNAMIC_USER_PATH_COUNTERS[key]

    metric_name = f"http_requests_user_{sanitize_metric_part(user_id)}_path_{sanitize_metric_part(path)}_total"
    counter = Counter(
        metric_name,
        f"HTTP requests for user_id={user_id} path={path}",
        registry=registry,
    )
    DYNAMIC_USER_PATH_COUNTERS[key] = counter
    return counter

@app.before_request
def track_request():
    if request.path == "/metrics":
        return

    user_id = request.headers.get("X-User-Id", request.args.get("user_id", "anonymous"))
    session_id = request.headers.get("X-Session-Id", request.args.get("session_id", "unknown"))
    path = request.full_path.rstrip("?") if request.query_string else request.path

    REQUESTS_TOTAL.labels(
        user_id=user_id,
        session_id=session_id,
        path=path,
    ).inc()

    get_or_create_user_path_counter(user_id, path).inc()

@app.route("/")
def index():
    return {
        "status": "ok",
        "message": "Prometheus metrics demo",
    }

@app.route("/hello/<name>")
def hello(name):
    return {
        "message": f"Hello, {name}",
    }

@app.route("/metrics")
def metrics():
    return Response(generate_latest(registry), mimetype=CONTENT_TYPE_LATEST)

if __name__ == "__main__":
    port = int(os.getenv("PORT", "8000"))
    app.run(host="0.0.0.0", port=port)